UPDATE TB_CONSTRUCTION SET name = #{name}, location = #{location}, address = #{address}, conManager = #{conManager}, conContact = #{conContact}, manager = #{manager}, contact = #{contact}
, groupIdx = #{groupIdx} , fcIdx = if(#{fcIdx} = 0, null, #{fcIdx})
